## 4\. W3C Trace Context Integration [Link to 4. W3C Trace Context Integration](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#4-w3c-trace-context-integration)

W3C Trace Context is the standard for distributed tracing propagation. It uses two headers:

- **traceparent**: Contains version, trace-id, parent-id, and trace-flags
- **tracestate**: Vendor-specific key-value pairs

```plaintext
TextCopy
traceparent: 00-4bf92f3577b34da6a3ce929d0e0e4736-00f067aa0ba902b7-01
             |  |                                |                |
             v  |                                |                |
          version                                |                |
                |                                |                |
                v                                |                |
             trace-id (32 hex chars)             |                |
                                                 v                |
                                           parent-id (16 hex)     |
                                                                  v
                                                            trace-flags
```

### Linking Request ID to Trace ID [Link to Linking Request ID to Trace ID](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#linking-request-id-to-trace-id)

The key insight: **your request ID and trace ID can be the same thing**, or you can maintain a mapping between them.

#### Option A: Use Trace ID as Request ID [Link to Option A: Use Trace ID as Request ID](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#option-a-use-trace-id-as-request-id)

```typescript
TypeScriptCopy
import { trace, context } from '@opentelemetry/api';

function getRequestIdFromTrace(): string {
  const span = trace.getSpan(context.active());
  if (span) {
    const spanContext = span.spanContext();
    return spanContext.traceId;
  }
  return randomUUID();
}

function traceAwareRequestMiddleware(req: Request, res: Response, next: NextFunction) {
  const span = trace.getSpan(context.active());

  if (span) {
    const traceId = span.spanContext().traceId;
    req.requestId = traceId;
    res.set('x-request-id', traceId);
    res.set('x-trace-id', traceId);
  }

  next();
}
```

#### Option B: Maintain Separate IDs with Mapping [Link to Option B: Maintain Separate IDs with Mapping](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#option-b-maintain-separate-ids-with-mapping)

```typescript
TypeScriptCopy
function dualIdMiddleware(req: Request, res: Response, next: NextFunction) {
  const span = trace.getSpan(context.active());
  const requestId = req.get('x-request-id') || randomUUID();

  req.requestId = requestId;
  res.set('x-request-id', requestId);

  if (span) {
    const traceId = span.spanContext().traceId;
    res.set('x-trace-id', traceId);

    // Add request ID as span attribute for correlation
    span.setAttribute('http.request_id', requestId);
  }

  next();
}
```

### Full W3C Trace Context Propagation [Link to Full W3C Trace Context Propagation](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#full-w3c-trace-context-propagation)

```typescript
TypeScriptCopy
import { propagation, context, trace, SpanKind } from '@opentelemetry/api';

// Extracting context from incoming request
function extractTraceContext(req: Request): void {
  const carrier = {
    traceparent: req.get('traceparent'),
    tracestate: req.get('tracestate'),
  };

  const extractedContext = propagation.extract(context.active(), carrier);
  // Now extractedContext contains the parent span context
}

// Injecting context into outgoing request
async function makeTracedRequest(url: string, options: RequestInit = {}): Promise<Response> {
  const tracer = trace.getTracer('http-client');

  return tracer.startActiveSpan('http.request', { kind: SpanKind.CLIENT }, async (span) => {
    try {
      const headers: Record<string, string> = { ...(options.headers as Record<string, string>) };

      // Inject trace context into outgoing headers
      propagation.inject(context.active(), headers);

      span.setAttribute('http.url', url);
      span.setAttribute('http.method', options.method || 'GET');

      const response = await fetch(url, { ...options, headers });

      span.setAttribute('http.status_code', response.status);
      return response;
    } finally {
      span.end();
    }
  });
}
```

