### Error Responses with Correlation [Link to Error Responses with Correlation](https://oneuptime.com/blog/post/2026-01-30-request-trace-correlation/view\#error-responses-with-correlation)

```typescript
TypeScriptCopy
interface ErrorResponse {
  error: string;
  message: string;
  requestId: string;
  traceId?: string;
  timestamp: string;
}

function errorHandler(err: Error, req: Request, res: Response, next: NextFunction) {
  const span = trace.getSpan(context.active());
  const traceId = span?.spanContext().traceId;

  // Record error in span
  if (span) {
    span.recordException(err);
    span.setStatus({ code: 2, message: err.message }); // ERROR status
  }

  const errorResponse: ErrorResponse = {
    error: err.name,
    message: err.message,
    requestId: req.requestId || 'unknown',
    traceId,
    timestamp: new Date().toISOString(),
  };

  // Log with correlation
  console.error(JSON.stringify({
    level: 'error',
    ...errorResponse,
    stack: err.stack,
  }));

  res.status(500).json(errorResponse);
}
```

